module top_module(
    input  D   ,
    output Q   ,
    input  CLK ,
    input  VPB ,
    input  VPWR,
    input  VGND,
    input  VNB
);// Declare any necessary wires or registers
    reg obf_Q_reg;

    // Always block for clocking
    always @(posedge CLK) begin
        obf_Q_reg <= D;
    end

    // Assign output Q to obf_Q_reg
    assign Q = obf_Q_reg;

endmodule
